void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("MorisDupon_1");			link.l1 = StringFromKey("MorisDupon_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("MorisDupon_3");			link.l1 = StringFromKey("MorisDupon_4");			link.l1.go = "exit";			NextDiag.TempNode = "2";		break;		case "2":			dialog.text = StringFromKey("MorisDupon_5");			link.l1 = StringFromKey("MorisDupon_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("MorisDupon_7");			link.l1 = StringFromKey("MorisDupon_8");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("MorisDupon_9");			link.l1 = StringFromKey("MorisDupon_10");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("MorisDupon_11");			link.l1 = StringFromKey("MorisDupon_12");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("MorisDupon_13");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "7";		break;		/* -------------------------------------------------------------------- */		case "7":			dialog.text = StringFromKey("MorisDupon_14");			link.l1 = StringFromKey("MorisDupon_15");			link.l1.go = "8";		break;		case "8":			dialog.text = StringFromKey("MorisDupon_16");			link.l1 = StringFromKey("MorisDupon_17");			link.l1.go = "9";		break;		case "9":			dialog.text = StringFromKey("MorisDupon_18");			link.l1 = StringFromKey("MorisDupon_19");			link.l1.go = "10";		break;		case "10":			dialog.text = StringFromKey("MorisDupon_20");			link.l1 = StringFromKey("MorisDupon_21");			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}